public class PayPalAdapter implements PaymentProcessor { private final PayPalGateway gateway = new PayPalGateway(); public boolean processPayment(String orderId, double amount) { String id = gateway.sendPayment(amount, orderId); return id != null; } public boolean refund(String transactionId) { return gateway.cancelPayment(transactionId); } public String getGatewayName() { return "PayPal"; } }